   120→  // Top 5 over and under running trains
   121→  const topOver = ranking?.trains.filter(t => t.status === 'over').slice(0, 5) || [];
   122→  const topUnder = ranking?.trains.filter(t => t.status === 'under').slice(0, 5) || [];
   123→
   124→  return (
   125→    <div className="space-y-6">
   126→      {/* Summary Stats */}
